/**
 * GENERATED COMPONENT — StageTimerDisplay
 * Domain: Live Events (Stagetimer)
 * Primitive: useComposableTimer
 * Generated by: AI from hook + domain context
 */

import { useComposableTimer } from '../../hooks/composable'

interface StageTimerDisplayProps {
  componentId: string
  listenToComponent?: string
  duration?: number
}

export function StageTimerDisplay({
  componentId,
  listenToComponent,
  duration = 300,
}: StageTimerDisplayProps) {
  const {
    remaining,
    isRunning,
    isComplete,
    progress,
    formatted,
    emitStart,
    emitStop,
    emitReset,
  } = useComposableTimer({
    componentId,
    listenToComponent,
    duration,
    direction: 'down',
  })

  // Color based on remaining time
  const timerColor = isComplete
    ? 'text-red-500'
    : remaining <= 30
      ? 'text-yellow-400'
      : 'text-white'

  const bgColor = isComplete
    ? 'from-red-950 to-red-900'
    : isRunning
      ? 'from-zinc-900 to-black'
      : 'from-zinc-800 to-zinc-900'

  return (
    <div className={`flex flex-col items-center justify-center bg-gradient-to-br ${bgColor} rounded-2xl p-12 min-h-[400px]`}>
      {/* Timer Display */}
      <div className={`text-9xl font-mono font-light tracking-wider ${timerColor} transition-colors`}>
        {formatted}
      </div>

      {/* Progress Bar */}
      <div className="w-full max-w-md mt-8 bg-zinc-800 rounded-full h-1.5 overflow-hidden">
        <div
          className={`h-full transition-all duration-1000 ${
            isComplete ? 'bg-red-500' : remaining <= 30 ? 'bg-yellow-400' : 'bg-green-500'
          }`}
          style={{ width: `${(1 - progress) * 100}%` }}
        />
      </div>

      {/* Status */}
      <div className="mt-4 text-sm text-zinc-500 uppercase tracking-widest">
        {isComplete ? 'Time\'s Up' : isRunning ? 'Running' : 'Ready'}
      </div>

      {/* Controls */}
      <div className="flex gap-4 mt-8">
        {!isRunning && !isComplete && (
          <button
            onClick={emitStart}
            className="px-8 py-3 bg-green-500 hover:bg-green-600 text-white rounded-xl text-lg font-medium transition-colors"
          >
            Start
          </button>
        )}
        {isRunning && (
          <button
            onClick={emitStop}
            className="px-8 py-3 bg-red-500 hover:bg-red-600 text-white rounded-xl text-lg font-medium transition-colors"
          >
            Stop
          </button>
        )}
        <button
          onClick={() => emitReset()}
          className="px-8 py-3 bg-zinc-700 hover:bg-zinc-600 text-white rounded-xl text-lg font-medium transition-colors"
        >
          Reset
        </button>
      </div>
    </div>
  )
}
